#include <vector>
#include <unordered_map>
#include <set>
using namespace std;

vector<long long> solve(long long c, vector<vector<long long>> connections, vector<vector<long long>> queries) {
    vector<long long> parent(c + 1, 0);
    vector<long long> rank(c + 1, 1);
    for (long long i = 1; i <= c; ++i) {
        parent[i] = i;
    }
    auto find = [&](long long x) -> long long {
        if (parent[x] != x) {
            parent[x] = find(parent[x]);
        }
        return parent[x];
    };
    auto union_ = [&](long long x, long long y) -> void {
        long long root_x = find(x);
        long long root_y = find(y);
        if (root_x != root_y) {
            if (rank[root_x] < rank[root_y]) {
                parent[root_x] = root_y;
            } else {
                parent[root_y] = root_x;
                if (rank[root_x] == rank[root_y]) {
                    rank[root_x]++;
                }
            }
        }
    };
    for (auto &conn : connections) {
        long long u = conn[0];
        long long v = conn[1];
        union_(u, v);
    }
    unordered_map<long long, set<long long>> component_sets;
    for (long long i = 1; i <= c; ++i) {
        long long root = find(i);
        component_sets[root].insert(i);
    }
    vector<bool> online(c + 1, true);
    vector<long long> result;
    for (auto &q : queries) {
        long long type = q[0];
        long long x = q[1];
        if (type == 1) {
            if (online[x]) {
                result.push_back(x);
            } else {
                long long root = find(x);
                if (component_sets[root].empty()) {
                    result.push_back(-1);
                } else {
                    result.push_back(*component_sets[root].begin());
                }
            }
        } else {
            online[x] = false;
            long long root = find(x);
            auto it = component_sets[root].find(x);
            if (it != component_sets[root].end()) {
                component_sets[root].erase(it);
            }
        }
    }
    return result;
}

