function solve(c, connections, queries) {
    const parent = Array(c + 1).fill(0).map((_, i) => i);
    const rank = Array(c + 1).fill(1);

    function find(x) {
        if (parent[x] !== x) {
            parent[x] = find(parent[x]);
        }
        return parent[x];
    }

    function union(x, y) {
        const rootX = find(x);
        const rootY = find(y);
        if (rootX !== rootY) {
            if (rank[rootX] < rank[rootY]) {
                parent[rootX] = rootY;
            } else {
                parent[rootY] = rootX;
                if (rank[rootX] === rank[rootY]) {
                    rank[rootX]++;
                }
            }
        }
    }

    for (const conn of connections) {
        const u = conn[0];
        const v = conn[1];
        union(u, v);
    }

    const componentData = new Map();
    const online = Array(c + 1).fill(true);

    for (let i = 1; i <= c; i++) {
        const root = find(i);
        if (!componentData.has(root)) {
            componentData.set(root, { stations: [], min_online: 0 });
        }
        componentData.get(root).stations.push(i);
    }

    for (const entry of componentData.entries()) {
        const comp = entry[1];
        comp.stations.sort((a, b) => a - b);
        comp.min_online = comp.stations[0];
    }

    const result = [];

    for (const q of queries) {
        const type = q[0];
        const x = q[1];
        if (type === 1) {
            if (online[x]) {
                result.push(x);
            } else {
                const root = find(x);
                const comp = componentData.get(root);
                if (comp.min_online === -1) {
                    result.push(-1);
                } else {
                    result.push(comp.min_online);
                }
            }
        } else {
            online[x] = false;
            const root = find(x);
            const comp = componentData.get(root);
            if (comp.min_online === x) {
                let new_min = -1;
                for (const station of comp.stations) {
                    if (online[station]) {
                        new_min = station;
                        break;
                    }
                }
                comp.min_online = new_min;
            }
        }
    }

    return result;
}
