function solve(c, connections, queries) {
    const parent = Array(c + 1).fill(0).map((_, i) => i);
    const rank = Array(c + 1).fill(1);

    function find(x) {
        if (parent[x] !== x) {
            parent[x] = find(parent[x]);
        }
        return parent[x];
    }

    function union(x, y) {
        const rootX = find(x);
        const rootY = find(y);
        if (rootX !== rootY) {
            if (rank[rootX] < rank[rootY]) {
                parent[rootX] = rootY;
            } else {
                parent[rootY] = rootX;
                if (rank[rootX] === rank[rootY]) {
                    rank[rootX]++;
                }
            }
        }
    }

    for (const [u, v] of connections) {
        union(u, v);
    }

    const componentMap = new Map();
    for (let i = 1; i <= c; i++) {
        const root = find(i);
        if (!componentMap.has(root)) {
            componentMap.set(root, []);
        }
        componentMap.get(root).push(i);
    }

    // Sort each component's stations
    for (const [root, stations] of componentMap.entries()) {
        stations.sort((a, b) => a - b);
    }

    const online = new Array(c + 1).fill(true);
    const result = [];

    for (const [type, x] of queries) {
        if (type === 1) {
            if (online[x]) {
                result.push(x);
            } else {
                const root = find(x);
                const componentStations = componentMap.get(root);
                let min = -1;
                for (const station of componentStations) {
                    if (online[station]) {
                        min = station;
                        break;
                    }
                }
                result.push(min);
            }
        } else {
            online[x] = false;
        }
    }

    return result;
}
